class Solution {
public:
    string originalDigits(string s) {
        vector<int> count(26, 0);
        for (char c : s) count[c - 'a']++;

        vector<int> digit_count(10, 0);
        digit_count[0] = count['z' - 'a'];
        digit_count[2] = count['w' - 'a'];
        digit_count[4] = count['u' - 'a'];
        digit_count[6] = count['x' - 'a'];
        digit_count[8] = count['g' - 'a'];

        digit_count[3] = count['h' - 'a'] - digit_count[8];
        digit_count[5] = count['f' - 'a'] - digit_count[4];
        digit_count[7] = count['s' - 'a'] - digit_count[6];

        digit_count[1] = count['o' - 'a'] - digit_count[0] - digit_count[2] - digit_count[4];
        digit_count[9] = count['i' - 'a'] - digit_count[5] - digit_count[6] - digit_count[8];

        string result;
        for (int i = 0; i < 10; ++i) {
            result += string(digit_count[i], '0' + i);
        }
        return result;
    }
};
```
